package evaluation

import "fmt"

// EvaluationError represents an error that occurred during flag evaluation,
// providing context about which flag was being evaluated and at what phase.
type EvaluationError struct {
	NamespaceKey string
	FlagKey      string
	Phase        string
	Err          error
}

func (e *EvaluationError) Error() string {
	return fmt.Sprintf("evaluating flag %q at phase %q: %s", e.NamespaceKey+"/"+e.FlagKey, e.Phase, e.Err.Error())
}

func (e *EvaluationError) Unwrap() error {
	return e.Err
}

func newEvaluationError(namespaceKey, flagKey, phase string, err error) *EvaluationError {
	return &EvaluationError{
		NamespaceKey: namespaceKey,
		FlagKey:      flagKey,
		Phase:        phase,
		Err:          err,
	}
}

